# Cache mtime-based de la liste des identités. _list_identities() est appelé
# ~30x par page-load ; chaque appel faisait un iterdir()+is_dir() sur le disque.
# On garde le resultat tant que le mtime de IDENTITIES_DIR n'a pas change (=
# aucun dossier d'identite ajoute/supprime). Zero staleness : creer/supprimer
# une identite change le mtime du dossier -> refresh immediat au prochain appel.
_IDENTITIES_CACHE = {"mtime": None, "v": []}


def _list_identities():
    if not IDENTITIES_DIR.exists():
        return []
    try:
        mt = IDENTITIES_DIR.stat().st_mtime_ns
    except Exception:
        mt = None
    if mt is not None and mt == _IDENTITIES_CACHE["mtime"]:
        return list(_IDENTITIES_CACHE["v"])
    v = sorted(p.name for p in IDENTITIES_DIR.iterdir() if p.is_dir())
    _IDENTITIES_CACHE["mtime"] = mt
    _IDENTITIES_CACHE["v"] = v
    return list(v)


# Identités réservées à Jailbreak : volontairement masquées des pages
# "Contenu / Bibliothèque" (Vue d'ensemble, Reels, Posts, Stories, Story CTA,
# Photos profil). Elles n'ont pas de médias à programmer — elles servent
# uniquement de référentiel de comptes dans la section Jailbreak.
# Pour en masquer une autre : ajoute son nom (en minuscules) ici.
JAILBREAK_ONLY_IDENTITIES = {"jessye"}


def _list_content_identities():
    """Identités affichées dans les pages Contenu/Bibliothèque : toutes SAUF
    celles réservées à Jailbreak (JAILBREAK_ONLY_IDENTITIES).
    Le backend (routes CRUD, page Jailbreak, VAs) continue d'utiliser
    _list_identities() — donc Jessye reste pleinement fonctionnelle ailleurs."""
    hidden = {h.lower() for h in JAILBREAK_ONLY_IDENTITIES}
    return [i for i in _list_identities() if i.lower() not in hidden]


# ============ Utilisateurs web (login user/password) ============

WEB_USERS_FILE = DATA_DIR / "web_admin_users.json"


def _hash_password(password: str) -> str:
    import hashlib
    return hashlib.sha256(password.encode("utf-8")).hexdigest()


def _load_web_users() -> dict:
    if not WEB_USERS_FILE.exists():
        return {}
    try:
        return json.loads(WEB_USERS_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _save_web_users(users: dict):
    WEB_USERS_FILE.parent.mkdir(parents=True, exist_ok=True)
    WEB_USERS_FILE.write_text(json.dumps(users, indent=2, ensure_ascii=False), encoding="utf-8")


def _bootstrap_web_users():
    """Crée le user 'samaali' avec le WEB_PASSWORD courant si pas déjà présent."""
    users = _load_web_users()
    if "samaali" not in users:
        users["samaali"] = {
            "password_hash": _hash_password(WEB_PASSWORD),
            "created_at": int(time.time()),
            "role": "admin",
        }
        _save_web_users(users)


def _check_web_login(username: str, password: str) -> bool:
    """Accepte 2 façons :
    1. username + password matchant un user enregistré dans web_admin_users.json
    2. password seul matchant WEB_PASSWORD (legacy, pour compat)
    """
    if not password:
        return False
    # Bootstrap au premier login
    _bootstrap_web_users()
    if username:
        users = _load_web_users()
        u = users.get(username.lower().strip())
        if u and u.get("password_hash") == _hash_password(password):
            return True
    # Fallback : password seul matchant WEB_PASSWORD
    if password == WEB_PASSWORD:
        return True
    return False


def _web_user_role(username: str, password: str) -> str:
    """Role de l'utilisateur web qui vient de se connecter.

    - Login par username : retourne le role enregistre dans web_admin_users.json.
    - Login par WEB_PASSWORD seul (legacy / owner) : retourne 'admin' (acces complet).
    """
    uname = (username or "").lower().strip()
    if uname:
        u = _load_web_users().get(uname)
        if u and u.get("password_hash") == _hash_password(password or ""):
            return (u.get("role") or "admin").lower()
    return "admin"


def _render_login(err=""):
    err_html = (
        f'<div class="err"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>{err}</div>'
        if err else ""
    )
    return LOGIN_HTML.replace("{err}", err_html)


# ============ PERF : cache TTL pour les fonctions lourdes ============
# Memoize avec expiration. Marche pour funcs(args hashables) -> any.
import time as _time_perf
import functools as _ft_perf
import threading as _th_perf

_TTL_CACHE: dict = {}
_TTL_CACHE_LOCK = _th_perf.Lock()


def ttl_cache(seconds: int = 30, max_entries: int = 256):
    """Decorator : memoize une fonction pour N secondes.

    Utilise pour les fonctions cher a calculer mais qu on appelle bcp
    (renders HTML, appels API externes, etc.). Auto-cleanup si > max_entries.
    """
    def deco(fn):
        cache_key_prefix = f"{fn.__module__}.{fn.__qualname__}"
        @_ft_perf.wraps(fn)
        def wrapper(*args, **kwargs):
            try:
                k = (cache_key_prefix, args, tuple(sorted(kwargs.items())))
            except TypeError:
                # args non-hashables -> bypass cache
                return fn(*args, **kwargs)
            now = _time_perf.time()
            with _TTL_CACHE_LOCK:
                hit = _TTL_CACHE.get(k)
                if hit and (now - hit[0]) < seconds:
                    return hit[1]
            # Compute hors lock pour ne pas bloquer d autres threads
            result = fn(*args, **kwargs)
            with _TTL_CACHE_LOCK:
                _TTL_CACHE[k] = (now, result)
                # Cleanup si trop d entrees
                if len(_TTL_CACHE) > max_entries:
                    # Drop les 50 plus vieilles
                    olds = sorted(_TTL_CACHE.items(), key=lambda x: x[1][0])[:50]
                    for kk, _ in olds:
                        _TTL_CACHE.pop(kk, None)
            return result
        wrapper.invalidate = lambda: [
            _TTL_CACHE.pop(k, None)
            for k in [kk for kk in list(_TTL_CACHE.keys()) if kk[0] == cache_key_prefix]
        ]
        return wrapper
    return deco


def _invalidate_all_ttl_cache():
    """Vide tout le cache TTL (a appeler apres une mutation importante)."""
    with _TTL_CACHE_LOCK:
        _TTL_CACHE.clear()


def _arg_cached(seconds: int = 60, key_args=()):
    """Cache TTL qui inclut des request.args dans la cle.

    Pour les renders qui depend de query string (mp_start/mp_end, home_period...).
    Hit du cache si meme (args fn, meme query string keys, dans le TTL).
    """
    def deco(fn):
        cache_key_prefix = f"{fn.__module__}.{fn.__qualname__}"
        @_ft_perf.wraps(fn)
        def wrapper(*args, **kwargs):
            try:
                from flask import request as _flask_req
                arg_vals = tuple(_flask_req.args.get(k, "") for k in key_args)
            except Exception:
                arg_vals = ()
            try:
                k = (cache_key_prefix, args, tuple(sorted(kwargs.items())), arg_vals)
            except TypeError:
                return fn(*args, **kwargs)
            now = _time_perf.time()
            with _TTL_CACHE_LOCK:
                hit = _TTL_CACHE.get(k)
                if hit and (now - hit[0]) < seconds:
                    return hit[1]
            result = fn(*args, **kwargs)
            with _TTL_CACHE_LOCK:
                _TTL_CACHE[k] = (now, result)
            return result
        wrapper.invalidate = lambda: [
            _TTL_CACHE.pop(k, None)
            for k in [kk for kk in list(_TTL_CACHE.keys()) if kk[0] == cache_key_prefix]
        ]
        return wrapper
    return deco


# ============ PERF : cache des JSON par mtime ============
# Cache simple { path_str: (mtime, parsed_data) }. Invalide automatiquement
# quand le fichier est modifie. Evite de re-parse N fois par page-load.
_JSON_MTIME_CACHE: dict = {}


def _cached_json_load(path) -> dict:
    """Lit un JSON et le met en cache par mtime. Re-parse uniquement si modifie."""
    try:
        p = path if hasattr(path, "exists") else Path(path)
        if not p.exists():
            return {}
        mtime = p.stat().st_mtime
        key = str(p.resolve())
        cached = _JSON_MTIME_CACHE.get(key)
        if cached and cached[0] == mtime:
            return cached[1]
        data = json.loads(p.read_text(encoding="utf-8"))
        _JSON_MTIME_CACHE[key] = (mtime, data)
        return data
    except Exception:
        return {}


def _invalidate_json_cache(path):
    """Force le re-load au prochain appel (apres un save manuel hors helper)."""
    try:
        p = path if hasattr(path, "exists") else Path(path)
        _JSON_MTIME_CACHE.pop(str(p.resolve()), None)
    except Exception:
        pass


def _load_users():
    return _cached_json_load(USERS_FILE)


def _save_users(users):
    USERS_FILE.parent.mkdir(parents=True, exist_ok=True)
    USERS_FILE.write_text(json.dumps(users, indent=2, ensure_ascii=False), encoding="utf-8")
    _invalidate_json_cache(USERS_FILE)


def _load_identities_config():
    if not IDENTITIES_CONFIG_FILE.exists():
        return {}
    try:
        return json.loads(IDENTITIES_CONFIG_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _count_files(d: Path, exts=None) -> int:
    if not d.exists():
        return 0
    if exts is None:
        return sum(1 for p in d.iterdir() if p.is_file())
    return sum(
        1 for p in d.iterdir()
        if p.is_file() and p.suffix.lower() in exts and ".example" not in p.name
    )


def _identity_stats(identity: str) -> dict:
    """Compte les contenus de cette identité."""
    base = IDENTITIES_DIR / identity
    reels = _count_files(base / "videos", VIDEO_EXTS)
    posts = _count_files(base / "posts", IMAGE_EXTS)
    stories = _count_files(base / "stories", IMAGE_EXTS)
    storyctas = _count_files(base / "storyctas", IMAGE_EXTS)
    # Bios / usernames / names from JSON files
    def _safe_len(p):
        if not p.exists():
            return 0
        try:
            return len(json.loads(p.read_text(encoding="utf-8")))
        except Exception:
            return 0
    bios = _safe_len(base / "bios.json")
    usernames = _safe_len(base / "usernames.json")
    names = _safe_len(base / "names.json")
    return {
        "reels": reels,
        "posts": posts,
        "stories": stories,
        "storyctas": storyctas,
        "bios": bios,
        "usernames": usernames,
        "names": names,
    }


# ============ VA -> Paiement (crypto ou taptap) ============
VA_PAYMENTS_FILE = DATA_DIR / "va_payments.json"

# Réseaux crypto par type (réutilise la convention MyPuls)
VA_CRYPTO_NETWORKS = {
    "USDC": ["Ethereum", "Tron", "Solana", "BSC", "Polygon", "Arbitrum", "Optimism", "Base"],
    "ETH": ["Ethereum", "Arbitrum", "Optimism", "Base", "BSC", "Polygon", "Solana"],
    "SOL": ["Solana", "Ethereum", "BSC"],
    "TRX": ["Tron"],
}
VA_CRYPTO_TYPES = list(VA_CRYPTO_NETWORKS.keys())

# Opérateurs TapTap (mobile money)
TAPTAP_NETWORKS = ["Orange Money", "MTN Mobile Money", "Moov Money",
                   "Wave", "Free Money", "Airtel Money", "Autre"]


def _load_va_payments() -> dict:
    if not VA_PAYMENTS_FILE.exists():
        return {}
    try:
        return json.loads(VA_PAYMENTS_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _save_va_payments(data: dict):
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    VA_PAYMENTS_FILE.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")


def _get_va_payment(user_id) -> dict:
    """Retourne {kind, crypto_type, crypto_network, crypto_address,
    taptap_number, taptap_network} ou dict vide."""
    return _load_va_payments().get(str(user_id), {})


def _set_va_payment(user_id, payload: dict):
    data = _load_va_payments()
    key = str(user_id)
    # Nettoyer : ne garder que les champs reconnus
    clean = {}
    kind = (payload.get("kind") or "").strip().lower()
    if kind not in ("crypto", "taptap"):
        # Vide = effacer
        if key in data:
            data.pop(key)
            _save_va_payments(data)
        return
    clean["kind"] = kind
    if kind == "crypto":
        ct = (payload.get("crypto_type") or "").strip().upper()
        if ct in VA_CRYPTO_TYPES:
            clean["crypto_type"] = ct
        clean["crypto_network"] = (payload.get("crypto_network") or "").strip()
        clean["crypto_address"] = (payload.get("crypto_address") or "").strip()[:200]
    else:  # taptap
        clean["taptap_number"] = (payload.get("taptap_number") or "").strip()[:30]
        clean["taptap_network"] = (payload.get("taptap_network") or "").strip()
    data[key] = clean
    _save_va_payments(data)


