# ============ VA -> GMS links mapping ============
VA_LINKS_FILE = DATA_DIR / "va_links.json"
VA_INSTA_3_FILE = DATA_DIR / "va_insta_accounts.json"


def _load_va_insta_3() -> dict:
    """Retourne {user_id_str: [{handle, email, password, totp_seed}, ...]}.

    Max 3 comptes par VA. Schema riche pour stocker les credentials.
    Migration auto : les anciennes entrees au format string ['h1','h2'] sont
    converties en [{handle:'h1',...}, ...] a la lecture.
    """
    if not VA_INSTA_3_FILE.exists():
        return {}
    try:
        raw = json.loads(VA_INSTA_3_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}
    # Migration : list[str] -> list[dict]
    out = {}
    for uid, lst in (raw or {}).items():
        clean = []
        for it in (lst or []):
            if isinstance(it, str):
                clean.append({"handle": it, "email": "", "password": "", "totp_seed": ""})
            elif isinstance(it, dict):
                clean.append({
                    "handle": (it.get("handle") or "").strip(),
                    "email": (it.get("email") or "").strip(),
                    "password": it.get("password") or "",
                    "totp_seed": (it.get("totp_seed") or "").strip(),
                })
        out[str(uid)] = clean[:3]
    return out


def _save_va_insta_3(data: dict):
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    VA_INSTA_3_FILE.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
    _invalidate_json_cache(VA_INSTA_3_FILE)


def _normalize_insta_handle(raw: str) -> str:
    """'@AmEliaXY ' -> 'ameliaxy'. Renvoie '' si non-valide."""
    if not raw:
        return ""
    h = raw.strip().lstrip("@").strip()
    import re as _re_h
    h = _re_h.sub(r"[^a-zA-Z0-9_.]", "", h).lower()
    if not h or len(h) > 30:
        return ""
    return h


def _set_insta_3_for_va(user_id, accounts: list):
    """accounts = liste de dicts {handle, email, password, totp_seed}.
    Limite : 3 pour les VAs Discord, illimitee pour les VAs manuels (manual_*).
    On accepte aussi des strings pour compat avec l'ancien /insta Discord."""
    data = _load_va_insta_3()
    key = str(user_id)
    is_manual = key.startswith("manual_")
    max_n = 99 if is_manual else 3
    clean = []
    seen_handles = set()
    for it in (accounts or []):
        if isinstance(it, str):
            h = _normalize_insta_handle(it)
            if h and h not in seen_handles:
                seen_handles.add(h)
                clean.append({"handle": h, "email": "", "password": "", "totp_seed": ""})
        elif isinstance(it, dict):
            h = _normalize_insta_handle(it.get("handle") or "")
            if h and h in seen_handles:
                continue
            if h:
                seen_handles.add(h)
            if not h and not (it.get("email") or it.get("password") or it.get("totp_seed")):
                continue
            clean.append({
                "handle": h,
                "email": (it.get("email") or "").strip(),
                "password": it.get("password") or "",
                "totp_seed": (it.get("totp_seed") or "").strip().replace(" ", ""),
            })
        if len(clean) >= max_n:
            break
    if clean:
        data[key] = clean
    else:
        data.pop(key, None)
    _save_va_insta_3(data)


def _get_insta_3_for_va(user_id) -> list:
    return _load_va_insta_3().get(str(user_id), [])


# ============ Refresh quotidien automatique des stats Insta (00:00) ============
# Architecture :
# - Etat persistant dans data/insta_refresh_state.json : {last_run_at, status,
#   in_progress_since, last_summary, error}
# - Lock (threading.Lock) pour eviter 2 refreshes simultanes
# - Boot smart-refresh + boucle daily 00:00:30
# - UI : badge "MAJ il y a Xh" + bouton 🔄 Forcer refresh

INSTA_REFRESH_STATE_FILE = DATA_DIR / "insta_refresh_state.json"
import threading as _threading_mod
_REFRESH_LOCK = _threading_mod.Lock()
# Lock dedie au cache stats : protege le read-modify-write de
# va_insta_3_stats_cache.json. Sans lui, les 4 workers paralleles du
# refresh s ecrasent mutuellement leurs ecritures (chaque worker load le
# fichier entier, ajoute SON handle, re-save le tout) -> la plupart des
# resultats sont perdus et les comptes restent "NON SCRAPÉ".
_CACHE_LOCK = _threading_mod.RLock()


def _load_refresh_state() -> dict:
    if not INSTA_REFRESH_STATE_FILE.exists():
        return {}
    try:
        return json.loads(INSTA_REFRESH_STATE_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _save_refresh_state(state: dict):
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    INSTA_REFRESH_STATE_FILE.write_text(json.dumps(state, indent=2, ensure_ascii=False), encoding="utf-8")


def _set_refresh_status(**kw):
    """Update partiel du state (merge)."""
    s = _load_refresh_state()
    s.update(kw)
    _save_refresh_state(s)


def _all_tracked_handles() -> set:
    """Tous les handles Insta tracked dans le bot (VAs + externals + jailbreak).

    Les comptes Jailbreak (stockes par identite dans jailbreak.json) sont
    inclus pour que leurs stats Insta (abos, vues 24h/sem/2sem, PP) soient
    scrapees automatiquement comme les VAs — sinon ils restent 'NON SCRAPÉ'.
    """
    handles = set()
    for accs in _load_va_insta_3().values():
        for a in accs:
            h = (a.get("handle") or "").strip()
            if h:
                handles.add(h)
    for it in _load_external_insta():
        h = (it.get("handle") or "").strip()
        if h:
            handles.add(h)
    # Jailbreak : tous les usernames de tous les comptes, toutes identites
    try:
        import jailbreak as _jb_h
        for _ident_data in _jb_h.list_all().values():
            if not isinstance(_ident_data, dict):
                continue
            for _acc in (_ident_data.get("accounts") or []):
                if not isinstance(_acc, dict):
                    continue  # defensif : entree malformee (string legacy)
                raw = (_acc.get("username") or "").strip()
                if not raw:
                    continue
                hn = _normalize_insta_handle(raw) if callable(_normalize_insta_handle) else raw.lower().lstrip("@")
                if hn:
                    handles.add(hn)
    except Exception as _e_jb:
        print(f"[insta-tracked] jailbreak handles skip: {_e_jb}", flush=True)
    return handles


def _do_refresh(handles: list, label: str = "manual") -> dict:
    """Core refresh : lock + parallel scrape + state persistence.

    Retourne {ok, banned, err, duration_s, total}.
    """
    from concurrent.futures import ThreadPoolExecutor, as_completed
    import time as _t_dr
    if not _REFRESH_LOCK.acquire(blocking=False):
        return {"error": "Un refresh est deja en cours", "ok": 0, "banned": 0, "err": 0}
    try:
        t0 = _t_dr.time()
        total = len(handles)
        _set_refresh_status(
            status="in_progress",
            in_progress_since=int(t0),
            in_progress_label=label,
            in_progress_total=total,
        )
        print(f"[insta-refresh:{label}] starting parallel for {total} handles", flush=True)
        ok = banned = err = 0
        def _scrape_one(h):
            try:
                return h, _compute_insta_3_stats(h, force=True), None
            except Exception as e:
                return h, None, e
        with ThreadPoolExecutor(max_workers=4) as ex:
            futures = [ex.submit(_scrape_one, h) for h in handles]
            for fut in as_completed(futures):
                h, res, exc = fut.result()
                if exc is not None:
                    err += 1
                elif res.get("banned"):
                    banned += 1
                elif res.get("error"):
                    err += 1
                else:
                    ok += 1
        dt_s = _t_dr.time() - t0
        summary = {
            "ok": ok, "banned": banned, "err": err,
            "duration_s": round(dt_s, 1), "total": total, "label": label,
            "finished_at": int(_t_dr.time()),
        }
        _set_refresh_status(
            status="idle",
            in_progress_since=None,
            in_progress_label=None,
            in_progress_total=None,
            last_run_at=int(_t_dr.time()),
            last_summary=summary,
            error=None,
        )
        print(f"[insta-refresh:{label}] done in {dt_s:.1f}s — ok={ok} banned={banned} err={err}", flush=True)
        return summary
    except Exception as e:
        _set_refresh_status(status="idle", in_progress_since=None, error=str(e))
        raise
    finally:
        _REFRESH_LOCK.release()


def _run_daily_insta_refresh():
    """Re-scrape TOUS les comptes Insta tracked (force, ignore le cache)."""
    handles = sorted(_all_tracked_handles())
    return _do_refresh(handles, label="daily")


# Heures de refresh Insta automatique (heure locale serveur).
# 3x/jour = stats bien fraiches (vues 24h/sem qui evoluent en continu).
_INSTA_REFRESH_HOURS = [0, 8, 16]


def _next_insta_refresh_dt(now):
    """Retourne le prochain datetime de refresh parmi _INSTA_REFRESH_HOURS.
    Cherche sur aujourd'hui + demain, retient le plus proche dans le futur."""
    import datetime as _dt_nx
    candidates = []
    for day_off in (0, 1):
        base = (now + _dt_nx.timedelta(days=day_off)).replace(
            minute=0, second=30, microsecond=0
        )
        for h in _INSTA_REFRESH_HOURS:
            dt = base.replace(hour=h)
            if dt > now:
                candidates.append(dt)
    return min(candidates) if candidates else (now + _dt_nx.timedelta(hours=8))


def _daily_insta_loop():
    """Thread daemon : refresh initial au boot + refresh recurrent 2-3x/jour.

    Tourne a chaque heure de _INSTA_REFRESH_HOURS (00h / 08h / 16h) pour que
    les vues 24h / semaine restent fraiches. Au boot, smart-refresh (skip les
    handles dont le cache est encore frais) pour ne pas hammerer IG."""
    import time as _t_dl
    import datetime as _dt_dl
    # Refresh initial au demarrage : seulement les handles stale (cache > TTL
    # ou jamais scrape). Evite de re-scrape inutilement au moindre redemarrage.
    try:
        _t_dl.sleep(30)  # attend que le bot soit stabilise (Discord ready, etc.)
        _run_daily_insta_refresh_smart()
    except Exception as e:
        print(f"[daily-insta] initial refresh crash: {e}", flush=True)
    # Boucle recurrente : 00h / 08h / 16h chaque jour
    while True:
        try:
            now = _dt_dl.datetime.now()
            nxt = _next_insta_refresh_dt(now)
            wait_s = (nxt - now).total_seconds()
            print(f"[daily-insta-loop] prochain refresh a {nxt.strftime('%d/%m %H:%M')} "
                  f"(dans {int(wait_s // 60)} min)", flush=True)
            _t_dl.sleep(max(60, wait_s))
            _run_daily_insta_refresh()
        except Exception as e:
            print(f"[daily-insta-loop] crash: {e}", flush=True)
            _t_dl.sleep(300)


def _run_daily_insta_refresh_smart():
    """Skip les handles dont le cache est encore frais (< _INSTA_3_STATS_TTL,
    soit 8h pour aligner le refresh 3x/jour).
    Utilise au boot pour pre-warmer sans hammerer IG en cas de redemarrage."""
    import time as _t_dr
    cache = _load_insta_3_stats_cache()
    now_ts = int(_t_dr.time())
    all_h = sorted(_all_tracked_handles())
    todo = [h for h in all_h if (
        h not in cache or (now_ts - int(cache.get(h, {}).get("scraped_at", 0))) >= _INSTA_3_STATS_TTL
    )]
    skipped = len(all_h) - len(todo)
    print(f"[insta-refresh:boot] {len(todo)} stale, {skipped} frais", flush=True)
    if not todo:
        # Pas de refresh necessaire : mais on enregistre quand meme un state idle
        _set_refresh_status(status="idle", last_check_at=now_ts)
        return {"ok": 0, "banned": 0, "err": 0, "duration_s": 0, "total": 0, "label": "boot-noop"}
    return _do_refresh(todo, label="boot-smart")


_DAILY_THREAD_STARTED = False

def _start_daily_insta_thread():
    global _DAILY_THREAD_STARTED
    if _DAILY_THREAD_STARTED:
        return
    _DAILY_THREAD_STARTED = True
    import threading as _th
    t = _th.Thread(target=_daily_insta_loop, daemon=True, name="daily-insta-refresh")
    t.start()
    _hrs = "h / ".join(str(h).zfill(2) for h in _INSTA_REFRESH_HOURS) + "h"
    print(f"[daily-insta] thread started — refresh {_hrs} (3x/jour)", flush=True)


def _render_refresh_status_text(st: dict) -> str:
    """Texte court à afficher dans le widget refresh."""
    import time as _t_r, datetime as _dt_r
    if st.get("status") == "in_progress":
        since = int(st.get("in_progress_since") or 0)
        elapsed = int(_t_r.time()) - since if since else 0
        total = st.get("in_progress_total") or 0
        return f"⏳ Refresh en cours ({elapsed}s / {total} comptes)"
    last = int(st.get("last_run_at") or 0)
    if not last:
        return "⏸ Jamais refresh"
    age = int(_t_r.time()) - last
    if age < 60:
        ago = "à l'instant"
    elif age < 3600:
        ago = f"il y a {age // 60} min"
    elif age < 86400:
        ago = f"il y a {age // 3600}h"
    else:
        ago = f"il y a {age // 86400}j"
    summary = st.get("last_summary") or {}
    extra = ""
    if summary:
        extra = f" · {summary.get('ok',0)}✓ {summary.get('banned',0)}🚫"
    return f"✓ MAJ {ago}{extra}"


# ============ Comptes Insta externes (non lies a un VA Discord) ============
# Pour les VAs / personnes qui gerent bcp de comptes IG sans etre dans Discord.
# Storage : data/external_insta_accounts.json = list[{handle, password, totp_seed, added_at}]
EXT_INSTA_FILE = DATA_DIR / "external_insta_accounts.json"


def _load_external_insta() -> list:
    if not EXT_INSTA_FILE.exists():
        return []
    try:
        d = json.loads(EXT_INSTA_FILE.read_text(encoding="utf-8"))
        return d if isinstance(d, list) else []
    except Exception:
        return []


def _save_external_insta(items: list):
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    EXT_INSTA_FILE.write_text(json.dumps(items, indent=2, ensure_ascii=False), encoding="utf-8")
    _invalidate_json_cache(EXT_INSTA_FILE)


def _add_external_insta(handle: str, password: str = "", totp_seed: str = "",
                         va_name: str = "", model: str = "") -> dict:
    """Ajoute un compte. Retourne {ok, added/skipped, item}."""
    import time as _t
    h = _normalize_insta_handle(handle or "")
    if not h:
        return {"ok": False, "error": "handle invalide"}
    items = _load_external_insta()
    if any(it.get("handle") == h for it in items):
        return {"ok": False, "skipped": True, "error": "deja present"}
    item = {
        "handle": h,
        "password": (password or "").strip(),
        "totp_seed": (totp_seed or "").strip().replace(" ", ""),
        "va_name": (va_name or "").strip(),
        "model": (model or "").strip().title(),  # 'amelia' -> 'Amelia'
        "added_at": int(_t.time()),
    }
    items.append(item)
    _save_external_insta(items)
    return {"ok": True, "added": True, "item": item}


def _remove_external_insta(handle: str) -> bool:
    h = _normalize_insta_handle(handle or "")
    if not h:
        return False
    items = _load_external_insta()
    new_items = [it for it in items if it.get("handle") != h]
    if len(new_items) == len(items):
        return False
    _save_external_insta(new_items)
    return True


# ============ Stats Insta 3 (RapidAPI + cache 1h) ============

VA_INSTA_3_STATS_FILE = DATA_DIR / "va_insta_3_stats_cache.json"
_INSTA_3_STATS_TTL = 8 * 3600  # 8h (refresh auto 3x/jour : 00h / 08h / 16h)


def _load_insta_3_stats_cache() -> dict:
    if not VA_INSTA_3_STATS_FILE.exists():
        return {}
    try:
        return json.loads(VA_INSTA_3_STATS_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _save_insta_3_stats_cache(d: dict):
    """Ecriture atomique (temp + replace) pour ne jamais laisser un fichier
    JSON tronque si 2 ecritures se croisent ou si le process meurt en plein
    write."""
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    tmp = VA_INSTA_3_STATS_FILE.with_suffix(".json.tmp")
    tmp.write_text(json.dumps(d, indent=2, ensure_ascii=False), encoding="utf-8")
    import os as _os_sv
    _os_sv.replace(tmp, VA_INSTA_3_STATS_FILE)


def _cache_put_stats(handle: str, entry: dict):
    """Merge thread-safe d UN handle dans le cache stats.

    Re-load le fichier SOUS le lock juste avant d ecrire, pour ne pas
    ecraser les ecritures concurrentes des autres workers (sinon la plupart
    des resultats du refresh parallele sont perdus). C est le fix du bug
    'tout reste NON SCRAPÉ'."""
    with _CACHE_LOCK:
        cur = _load_insta_3_stats_cache()
        cur[handle] = entry
        _save_insta_3_stats_cache(cur)


def _verify_ig_profile_exists(handle: str) -> bool:
    """Probe sur instagram.com pour verifier qu'un compte existe.

    Instagram redirige tout vers le SPA donc on doit parser le HTML pour
    distinguer une vraie page de profil d'un 404.
    """
    try:
        import requests
        r = requests.get(
            f"https://www.instagram.com/{handle}/",
            timeout=10,
            headers={
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
                "Accept-Language": "en-US,en;q=0.9",
            },
            allow_redirects=True,
        )
    except Exception:
        return False
    if r.status_code != 200:
        return False
    txt = r.text or ""
    # Marqueurs explicites de page introuvable
    not_found_markers = [
        "Page Not Found",
        "Sorry, this page isn",  # "Sorry, this page isn't available"
        "Désolé, cette page n",
        '"is_private":true,"username":"' + handle.lower() + '"',  # private mais existe
    ]
    if any(m in txt for m in not_found_markers[:3]):
        return False
    # Marqueur positif : og:title contient le username
    if f'@{handle.lower()}' in txt.lower() or f'"username":"{handle.lower()}"' in txt.lower():
        return True
    # Par defaut on suppose qu'il existe si pas de marqueur de 404
    return True


def _scrape_via_ig_public(handle: str) -> dict:
    """Scrape un profil via l'endpoint public web_profile_info (free, no-auth).

    Retourne {profile: {...}, reels: [...]} au format compatible
    avec ce que scrape_profile renvoie.

    Anti-429 : petit jitter avant la requete (desynchronise les 4 workers
    paralleles), + 1 retry avec backoff si Instagram renvoie un rate-limit
    429. Evite que tout un batch (~40 handles) parte exactement en meme
    temps et se fasse jeter d un coup.
    """
    import requests
    import time as _t_sc
    import random as _rnd_sc
    # Jitter initial 0-1.2s : etale les departs des workers concurrents
    _t_sc.sleep(_rnd_sc.uniform(0.0, 1.2))
    _headers = {
        "X-IG-App-ID": "936619743392459",
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        "Accept": "*/*",
        "Accept-Language": "en-US,en;q=0.9",
    }
    _url = f"https://www.instagram.com/api/v1/users/web_profile_info/?username={handle}"
    r = None
    for _attempt in range(2):  # 1 essai + 1 retry sur 429
        try:
            r = requests.get(_url, headers=_headers, timeout=15)
        except Exception as e:
            return {"error": f"reseau IG public: {e}"}
        if r.status_code == 429 and _attempt == 0:
            # Backoff avant retry : 3-6s + jitter
            _t_sc.sleep(_rnd_sc.uniform(3.0, 6.0))
            continue
        break
    if r is None:
        return {"error": "reseau IG public: pas de reponse"}
    if r.status_code == 404:
        return {"error": f"🚫 Compte banni ou supprimé (@{handle})", "banned": True}
    if r.status_code == 429:
        return {"error": "Instagram rate-limit (429). Réessaie dans qq minutes."}
    if r.status_code != 200:
        return {"error": f"Instagram HTTP {r.status_code}"}
    try:
        d = r.json()
    except Exception:
        return {"error": "Reponse non-JSON"}
    user = (d.get("data") or {}).get("user") or {}
    if not user:
        return {"error": f"🚫 Compte banni ou introuvable (@{handle})", "banned": True}
    profile = {
        "username": user.get("username") or handle,
        "full_name": user.get("full_name") or "",
        "followers": (user.get("edge_followed_by") or {}).get("count", 0),
        "following": (user.get("edge_follow") or {}).get("count", 0),
        "posts_count": (user.get("edge_owner_to_timeline_media") or {}).get("count", 0),
        "profile_pic_url": user.get("profile_pic_url_hd") or user.get("profile_pic_url") or "",
        "biography": (user.get("biography") or "")[:300],
        "is_private": user.get("is_private", False),
        "is_verified": user.get("is_verified", False),
    }
    reels = []
    for edge in (user.get("edge_owner_to_timeline_media") or {}).get("edges", []):
        n = edge.get("node") or {}
        is_video = bool(n.get("is_video"))
        reels.append({
            "shortcode": n.get("shortcode") or "",
            "is_video": is_video,
            "views": n.get("video_view_count") or n.get("video_play_count") or 0,
            "likes": (n.get("edge_liked_by") or {}).get("count", 0),
            "comments": (n.get("edge_media_to_comment") or {}).get("count", 0),
            "taken_at": n.get("taken_at_timestamp"),
            "thumbnail_url": n.get("thumbnail_src") or n.get("display_url"),
            "url": f"https://www.instagram.com/p/{n.get('shortcode')}/" if n.get("shortcode") else "",
        })
    return {"profile": profile, "reels": reels}


def _compute_insta_3_stats(handle: str, force: bool = False) -> dict:
    """Pour un handle IG, retourne {daily, weekly, biweekly, followers, profile_pic_url, ...}.

    Strategy : Instagram public web_profile_info en premier (gratuit, fiable
    pour tous les comptes meme petits/recents). Si echec → fallback RapidAPI
    via insta_scraper. Cache 1h.
    """
    import time as _t
    h = (handle or "").strip().lstrip("@").lower()
    if not h:
        return {"error": "handle vide"}
    cache = _load_insta_3_stats_cache()
    now_ts = int(_t.time())
    cached = cache.get(h)
    # On n'utilise le cache que si on a un succes (pas d'erreur) ET dans le TTL
    if (cached and not force
            and not cached.get("error")
            and (now_ts - int(cached.get("scraped_at", 0))) < _INSTA_3_STATS_TTL):
        return cached
    # 1) Public IG d abord
    res = _scrape_via_ig_public(h)
    # 2) Fallback RapidAPI si l API publique echoue (sauf si banned : pas la
    #    peine de re-tenter, le compte n existe pas)
    if "error" in res and not res.get("banned"):
        try:
            import insta_scraper as _ig_s
            res2 = _ig_s.scrape_profile(h, limit=50)
            if "error" not in res2:
                res = res2
            else:
                # On garde le plus parlant des 2 messages
                res = {"error": f"IG public: {res['error']} | RapidAPI: {res2['error']}"}
        except Exception:
            pass
    if "error" in res:
        err_msg = res["error"]
        is_banned = bool(res.get("banned"))
        # Si RapidAPI dit "invalid username", on tente une verif HTTP directe
        # pour distinguer "handle inexistant" vs "compte trop neuf/petit non-indexe"
        if not is_banned and ("invalid" in err_msg.lower() or "missing username" in err_msg.lower()):
            exists = _verify_ig_profile_exists(h)
            if exists:
                err_msg = f"Compte @{h} existe mais RapidAPI ne l'indexe pas (trop nouveau / petit)."
            else:
                err_msg = f"🚫 Compte banni ou supprimé (@{h})"
                is_banned = True
        out = {"error": err_msg, "banned": is_banned, "scraped_at": now_ts}
        _cache_put_stats(h, out)
        return out

    import datetime as _dt_s
    now_dt = _dt_s.datetime.now(_dt_s.timezone.utc)
    daily = weekly = biweekly = 0
    last_post_at = None
    last_reel_at = None
    # Meta profile
    profile = res.get("profile") or {}
    if not profile and "followers" in res:
        profile = res
    profile_pic = profile.get("profile_pic_url") or ""
    followers = int(profile.get("followers") or 0)
    posts_count = int(profile.get("posts_count") or 0)
    reels = res.get("reels") or res.get("posts") or []
    for p in reels:
        try:
            d_raw = p.get("date") or p.get("taken_at") or p.get("created_at")
            if isinstance(d_raw, (int, float)):
                p_dt = _dt_s.datetime.fromtimestamp(d_raw, tz=_dt_s.timezone.utc)
            else:
                s = str(d_raw or "").replace("Z", "+00:00")
                p_dt = _dt_s.datetime.fromisoformat(s)
                if p_dt.tzinfo is None:
                    p_dt = p_dt.replace(tzinfo=_dt_s.timezone.utc)
        except Exception:
            continue
        age_h = (now_dt - p_dt).total_seconds() / 3600.0
        is_video = bool(p.get("is_video") or p.get("views"))
        views = int(p.get("views") or 0)
        if not last_post_at or p_dt > last_post_at:
            last_post_at = p_dt
        if is_video and (not last_reel_at or p_dt > last_reel_at):
            last_reel_at = p_dt
        if is_video and views > 0:
            if age_h <= 24:
                daily += views
            if age_h <= 24 * 7:
                weekly += views
            if age_h <= 24 * 14:
                biweekly += views
    # Top 4 reels (par date desc) pour la preview strip
    def _ts(p):
        try:
            d = p.get("date") or p.get("taken_at")
            if isinstance(d, (int, float)):
                return int(d)
            s = str(d or "").replace("Z", "+00:00")
            return int(_dt_s.datetime.fromisoformat(s).timestamp())
        except Exception:
            return 0
    sorted_reels = sorted(reels, key=_ts, reverse=True)
    preview = []
    for p in sorted_reels[:6]:  # 6 posts pour une grille 3x2 façon profil IG
        thumb = p.get("thumbnail_url") or p.get("display_url") or ""
        sc = p.get("shortcode") or ""
        preview.append({
            "shortcode": sc,
            "thumbnail_url": thumb,
            "views": int(p.get("views") or 0),
            "is_video": bool(p.get("is_video")),
        })
    out = {
        "daily": daily,
        "weekly": weekly,
        "biweekly": biweekly,
        "last_post_at": last_post_at.isoformat() if last_post_at else None,
        "last_reel_at": last_reel_at.isoformat() if last_reel_at else None,
        "scraped_at": now_ts,
        "profile_pic_url": profile_pic,
        "followers": followers,
        "posts_count": posts_count,
        "preview": preview,
    }
    _cache_put_stats(h, out)
    return out


def _kick_scrape_handles(handles, label: str = "kick-scrape") -> int:
    """Lance un scrape IMMEDIAT en arriere-plan pour une liste de handles.

    Sert a ce que les comptes fraichement ajoutes (Jailbreak, externals, ...)
    ne restent pas 'NON SCRAPÉ' jusqu au prochain cycle auto (00h/08h/16h).
    Non-bloquant : spawn un thread daemon et rend la main tout de suite.
    Retourne le nombre de handles uniques mis en file."""
    norm = []
    seen = set()
    for h in (handles or []):
        try:
            hn = _normalize_insta_handle(h) if callable(_normalize_insta_handle) else str(h or "").strip().lower().lstrip("@")
        except Exception:
            hn = str(h or "").strip().lower().lstrip("@")
        if hn and hn not in seen:
            seen.add(hn)
            norm.append(hn)
    if not norm:
        return 0
    import threading as _th_ks

    def _bg():
        from concurrent.futures import ThreadPoolExecutor
        try:
            with ThreadPoolExecutor(max_workers=min(4, len(norm))) as ex:
                # force=True : on veut les vraies stats tout de suite, pas un cache vide
                list(ex.map(lambda x: _compute_insta_3_stats(x, force=True), norm))
            print(f"[{label}] scrape immediat OK ({len(norm)} comptes)", flush=True)
        except Exception as e:
            print(f"[{label}] scrape immediat crash: {e}", flush=True)

    _th_ks.Thread(target=_bg, daemon=True, name=label).start()
    return len(norm)


def _load_va_links() -> dict:
    """Retourne {user_id_str: [link_id_1, link_id_2, ...]} (cache par mtime)."""
    return _cached_json_load(VA_LINKS_FILE)


def _save_va_links(data: dict):
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    VA_LINKS_FILE.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
    _invalidate_json_cache(VA_LINKS_FILE)


def _get_links_for_va(user_id) -> list:
    return _load_va_links().get(str(user_id), [])


def _set_links_for_va(user_id, link_ids: list):
    data = _load_va_links()
    key = str(user_id)
    if link_ids:
        data[key] = link_ids
    else:
        data.pop(key, None)
    _save_va_links(data)


# Cache simple pour les données quotidiennes GMS (TTL 5 min, module-level)
_VA_DAILY_CACHE: dict = {}
_VA_DAILY_TTL = 300  # 5 minutes


def _get_links_clicks_period(link_ids: list, days: int = 7) -> dict:
    """Retourne {total, daily: [...]} pour des liens GMS sur N jours.

    Daily est calculé à partir de list_recent_visitors (timestamps par visite).
    Cache 5 min.
    """
    import time as _t
    now = _t.time()
    key = "|".join(sorted(link_ids)) + f"|days={days}"
    cached = _VA_DAILY_CACHE.get(key)
    if cached and (now - cached[0]) < _VA_DAILY_TTL:
        return cached[1]
    result = {"total": 0, "daily": [0] * days}
    try:
        import gms
        import datetime as _dt3
        if not gms.is_configured() or not link_ids:
            _VA_DAILY_CACHE[key] = (now, result)
            return result
        # list_recent_visitors avec limit 100 (les param dates ne marchent pas
        # fiablement sur cette API, on filtre côté client).
        today = _dt3.date.today()
        start_date = today - _dt3.timedelta(days=days - 1)
        res = gms._call_tool("list_recent_visitors", {
            "link_ids": link_ids,
            "limit": 100,
        })
        if res.get("ok"):
            data = res.get("data") or {}
            visitors = data.get("data", []) if isinstance(data, dict) else []
            # Bucketer par jour
            buckets = {}  # iso_date -> count
            for v in visitors:
                ts = v.get("timestamp", "") if isinstance(v, dict) else ""
                if not ts:
                    continue
                try:
                    # Format "2026-05-29T09:00:47.000Z"
                    day = ts[:10]  # "2026-05-29"
                    if start_date.isoformat() <= day <= today.isoformat():
                        buckets[day] = buckets.get(day, 0) + 1
                except Exception:
                    pass
            # Construire le tableau dans l'ordre chronologique
            daily = []
            for i in range(days - 1, -1, -1):
                d = (today - _dt3.timedelta(days=i)).isoformat()
                daily.append(buckets.get(d, 0))
            result = {"total": sum(daily), "daily": daily}
        _VA_DAILY_CACHE[key] = (now, result)
        return result
    except Exception:
        return result


def _sparkline_svg(values: list, width: int = 90, height: int = 28, color: str = "#a855f7") -> str:
    """Mini sparkline avec area fill."""
    if not values:
        return ""
    n = len(values)
    if n < 2:
        return ""
    max_v = max(values) or 1
    pts = []
    for i, v in enumerate(values):
        x = (i / (n - 1)) * (width - 4) + 2
        y = height - 4 - (v / max_v) * (height - 8)
        pts.append(f"{x:.1f},{y:.1f}")
    pts_str = " ".join(pts)
    area_pts = f"2,{height} {pts_str} {width-2},{height}"
    grad_id = f"spk-{id(values) % 100000}"
    return (
        f"<svg width='{width}' height='{height}' viewBox='0 0 {width} {height}' style='overflow:visible;display:block'>"
        f"<defs><linearGradient id='{grad_id}' x1='0' x2='0' y1='0' y2='1'>"
        f"<stop offset='0%' stop-color='{color}' stop-opacity='.35'/>"
        f"<stop offset='100%' stop-color='{color}' stop-opacity='0'/>"
        f"</linearGradient></defs>"
        f"<polygon points='{area_pts}' fill='url(#{grad_id})'/>"
        f"<polyline points='{pts_str}' fill='none' stroke='{color}' stroke-width='1.8' stroke-linejoin='round' stroke-linecap='round'/>"
        f"</svg>"
    )


def _get_model_clicks_period(model_name: str, days: int = 7) -> dict:
    """Retourne {total, daily: [...]} pour un modèle sur N derniers jours.

    Réutilise _get_links_clicks_period en récupérant d'abord les links du modèle.
    """
    try:
        import gms
        if not gms.is_configured():
            return {"total": 0, "daily": [0] * days}
        grouped = gms.get_links_grouped_by_model()
        link_ids = grouped.get(model_name, [])
        if not link_ids:
            return {"total": 0, "daily": [0] * days}
        return _get_links_clicks_period(link_ids, days=days)
    except Exception:
        return {"total": 0, "daily": [0] * days}


def _render_gms_clicks_widget() -> str:
    """Widget clicks GMS par modèle — style Infloww : cartes compactes par identité."""
    try:
        import gms
        if not gms.is_configured():
            return ""
    except Exception:
        return ""

    from flask import request as _req
    import datetime as _dt

    today = _dt.date.today()

    # Période : current_h1 (1-15) ou current_h2 (16-end), avec switches prev_*
    period = "current_h2" if today.day > 15 else "current_h1"
    try:
        period = _req.args.get("va_clicks_period", period) or period
    except Exception:
        pass

    def _range_for(p):
        first_of_month = today.replace(day=1)
        if p == "current_h1":
            s = first_of_month
            e = min(first_of_month + _dt.timedelta(days=14), today)
        elif p == "current_h2":
            s = first_of_month + _dt.timedelta(days=15)
            if first_of_month.month == 12:
                nm = first_of_month.replace(year=first_of_month.year + 1, month=1)
            else:
                nm = first_of_month.replace(month=first_of_month.month + 1)
            e = min(nm - _dt.timedelta(days=1), today)
        elif p == "prev_h2":
            if first_of_month.month == 1:
                pf = first_of_month.replace(year=first_of_month.year - 1, month=12)
            else:
                pf = first_of_month.replace(month=first_of_month.month - 1)
            s = pf + _dt.timedelta(days=15)
            e = first_of_month - _dt.timedelta(days=1)
        else:
            if first_of_month.month == 1:
                pf = first_of_month.replace(year=first_of_month.year - 1, month=12)
            else:
                pf = first_of_month.replace(month=first_of_month.month - 1)
            s = pf
            e = pf + _dt.timedelta(days=14)
        return s, e

    start_dt, end_dt = _range_for(period)
    days_count = (end_dt - start_dt).days + 1

    # Limiter aux modèles principaux (qui correspondent aux identités du bot)
    identities = _list_content_identities()
    ident_to_model = {ident: ident.capitalize() for ident in identities}
    sorted_models = [ident_to_model[i] for i in sorted(identities)]

    # Fetch en parallèle pour les 5 modèles (3-5x plus rapide que séquentiel)
    from concurrent.futures import ThreadPoolExecutor
    sorted_idents = sorted(identities)

    def _fetch_one(ident):
        try:
            return ident, _get_model_clicks_period(ident_to_model[ident], days=days_count)
        except Exception:
            return ident, {"total": 0, "daily": [0] * days_count}

    results = {}
    try:
        with ThreadPoolExecutor(max_workers=min(8, len(sorted_idents) or 1)) as pool:
            for ident, data in pool.map(_fetch_one, sorted_idents):
                results[ident] = data
    except Exception:
        for ident in sorted_idents:
            results[ident] = {"total": 0, "daily": [0] * days_count}

    cards_html = []
    total_clicks = 0
    total_visitors = 0
    # Pré-calculer le grouping une fois (cache déjà au niveau gms)
    grouped_links = gms.get_links_grouped_by_model()
    for ident in sorted_idents:
        model = ident_to_model[ident]
        data = results.get(ident) or {"total": 0, "daily": [0] * days_count}
        clicks = int(data.get("total", 0))
        daily = data.get("daily", []) or [0] * days_count
        total_clicks += clicks

        # Avatar identité
        avatar_url = _identity_avatar_url(ident)
        avatar_html = (
            f"<img src='{avatar_url}' class='vac-card-avatar' alt='{ident}' loading='lazy'>"
            if avatar_url else
            f"<div class='vac-card-avatar vac-card-avatar-fallback'>{ident[:1].upper()}</div>"
        )

        # Trend
        if clicks > 0 and len(daily) >= 2:
            trend_up = daily[-1] >= daily[-2]
            trend_color = "#22c55e" if trend_up else "#ef4444"
            trend_arrow = "↑" if trend_up else "↓"
        else:
            trend_color = "#6b7280"
            trend_arrow = "—"

        # Sparkline
        spark_color = "#3b82f6" if clicks > 0 else "#6b7280"
        spark = _sparkline_svg(daily, width=140, height=32, color=spark_color)

        n_links = len(grouped_links.get(model, []))
        cards_html.append(
            f"<div class='vac-card'>"
            f"<div class='vac-card-head'>"
            f"{avatar_html}"
            f"<div class='vac-card-info'>"
            f"<div class='vac-card-name'>@{ident}</div>"
            f"<div class='vac-card-sub'>{n_links} lien{'s' if n_links > 1 else ''}</div>"
            f"</div>"
            f"<div class='vac-card-trend' style='color:{trend_color}'>{trend_arrow}</div>"
            f"</div>"
            f"<div class='vac-card-value'>{clicks:,}</div>"
            f"<div class='vac-card-label'>clicks</div>"
            f"<div class='vac-card-spark'>{spark}</div>"
            f"</div>"
        )

    if not cards_html:
        return ""

    def _btn(p, txt):
        active = "vac-btn-active" if p == period else ""
        return f"<a href='?tab=valist&va_clicks_period={p}' class='vac-btn {active}'>{txt}</a>"

    mois_fr = ["janv", "févr", "mars", "avr", "mai", "juin",
               "juil", "août", "sept", "oct", "nov", "déc"]
    period_label_short = f"{start_dt.day} → {end_dt.day} {mois_fr[start_dt.month - 1]}"

    css = """
<style>
.vac-widget{background:#0f1116;border:1px solid #2a2a2a;border-radius:14px;padding:18px 20px;margin-bottom:20px}
.vac-head{display:flex;align-items:center;justify-content:space-between;gap:14px;margin-bottom:18px;flex-wrap:wrap}
.vac-title{display:flex;align-items:center;gap:8px;font-weight:700;font-size:15px;letter-spacing:-.01em}
.vac-title svg{color:#3b82f6}
.vac-subtitle{font-size:11px;color:#888;font-weight:400;margin-left:6px}
.vac-period-row{display:flex;gap:5px;flex-wrap:wrap}
.vac-btn{padding:6px 12px;background:transparent;border:1px solid #2a2a2a;color:#aaa;border-radius:7px;font-size:12px;font-weight:600;text-decoration:none;transition:all .15s}
.vac-btn:hover{background:rgba(255,255,255,.05);color:#fff}
.vac-btn-active{background:#3b82f6 !important;border-color:#3b82f6 !important;color:#fff !important}
/* Grid de cartes par modèle */
.vac-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:12px}
.vac-card{background:#1a1a1a;border:1px solid #2a2a2a;border-radius:12px;padding:14px;display:flex;flex-direction:column;gap:6px;transition:all .15s;position:relative;overflow:hidden}
.vac-card:hover{border-color:rgba(59,130,246,.4);transform:translateY(-2px)}
.vac-card-head{display:flex;align-items:center;gap:10px}
.vac-card-avatar{width:36px;height:36px;border-radius:50%;object-fit:cover;border:2px solid #2a2a2a;flex-shrink:0}
.vac-card-avatar-fallback{background:linear-gradient(135deg,#3b82f6,#a855f7);display:flex;align-items:center;justify-content:center;color:#fff;font-weight:800;font-size:15px;border:0}
.vac-card-info{flex:1;min-width:0}
.vac-card-name{font-weight:700;font-size:13px;letter-spacing:-.01em;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.vac-card-sub{font-size:10px;color:#888;margin-top:2px;font-weight:600;text-transform:uppercase;letter-spacing:.04em}
.vac-card-trend{font-size:16px;font-weight:800;line-height:1}
.vac-card-value{font-size:28px;font-weight:800;letter-spacing:-.03em;line-height:1;margin-top:4px}
.vac-card-label{font-size:11px;color:#888;font-weight:600;letter-spacing:.02em}
.vac-card-spark{margin-top:auto;display:flex;align-items:center;justify-content:center;opacity:.9}
body.light .vac-widget{background:#fff;border-color:#e5e7eb}
body.light .vac-btn{color:#666;border-color:#e5e7eb}
body.light .vac-btn:hover{background:#f3f4f6;color:#111}
body.light .vac-card{background:#f9fafb;border-color:#e5e7eb}
body.light .vac-card-name{color:#111}
</style>
"""

    return (
        css
        + "<div class='vac-widget'>"
        + "<div class='vac-head'>"
        + "<div class='vac-title'>"
        + "<svg viewBox='0 0 24 24' width='18' height='18' fill='none' stroke='currentColor' stroke-width='2.2'><path d='M22 12h-4l-3 9L9 3l-3 9H2'/></svg>"
        + f"Performance des modèles<span class='vac-subtitle'>{period_label_short} · {total_clicks} clicks</span>"
        + "</div>"
        + "<div class='vac-period-row'>"
        + _btn("prev_h1", "M-1 · 1-15")
        + _btn("prev_h2", "M-1 · 16-fin")
        + _btn("current_h1", "Ce mois · 1-15")
        + _btn("current_h2", "Ce mois · 16-fin")
        + "</div>"
        + "</div>"
        + "<div class='vac-grid'>"
        + "".join(cards_html)
        + "</div>"
        + "</div>"
    )


