# Roles restreints -> ensemble d'onglets (par 'name' showTab) visibles. owner /
# admin (ou role non liste ici) = acces complet. Un Chatter ne voit QUE la
# section Chatteurs (planning + revenus) + son profil + ses preferences.
_ROLE_ALLOWED_TABS = {
    "chatter": {"chatplanning", "revenus", "saccount", "sprefs"},
}


def _role_allowed_tabs(role):
    """Set d'onglets autorises pour un role, ou None = acces complet (owner/admin
    et tout role non explicitement restreint)."""
    r = (role or "").lower().strip()
    if r in ("", "owner", "admin"):
        return None
    return _ROLE_ALLOWED_TABS.get(r)


def _role_gate_script(allowed) -> str:
    """Script injecte (roles restreints uniquement) : cache les boutons sidebar,
    groupes/sections vides et panneaux non autorises, puis active l'onglet par
    defaut. Le CONTENU sensible est deja vide cote serveur (cf _render_upload_inner) ;
    ceci nettoie la navigation pour que l'employe ne voie que ses onglets."""
    import json as _json
    allowed_js = _json.dumps(sorted(allowed))
    return (
        "<script>(function(){"
        "var A=" + allowed_js + ";if(!A||!A.length)return;"
        "var ok={};A.forEach(function(n){ok[n]=1;});"
        "function nm(b){var o=b.getAttribute('onclick')||'';"
        "var m=o.match(/showTab\\(\\s*'[^']*'\\s*,\\s*'([^']*)'/);"
        "if(m)return m[1];return (b.id&&b.id.indexOf('tab-')===0)?b.id.slice(4):'';}"
        "function run(){"
        "document.querySelectorAll('.sidebar .item').forEach(function(b){var n=nm(b);if(n&&!ok[n])b.style.display='none';});"
        "document.querySelectorAll('.sidebar .group, .sidebar .solo-group').forEach(function(g){"
        "var it=g.querySelectorAll('.item'),v=false;Array.prototype.forEach.call(it,function(b){if(b.style.display!=='none')v=true;});"
        "if(it.length&&!v)g.style.display='none';});"
        "document.querySelectorAll('.sidebar .section-label').forEach(function(l){"
        "var n=l.nextElementSibling,v=false;while(n&&!(n.classList&&n.classList.contains('section-label'))){if(n.style.display!=='none')v=true;n=n.nextElementSibling;}"
        "if(!v)l.style.display='none';});"
        "document.querySelectorAll('.form-section').forEach(function(s){var id=s.id||'';if(id.indexOf('form-')===0&&!ok[id.slice(5)])s.remove();});"
        "var db=document.getElementById('tab-'+A[0]);if(db)db.click();"
        "}"
        "if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',run);}else{run();}"
        "})();</script>"
    )


def _get_all_roles():
    """Retourne la liste unifiee des roles (defauts + custom). Source unique
    de verite pour le tableau ET le dropdown 'Ajouter un utilisateur'."""
    role_defs = _load_role_definitions()
    default_roles = [
        ("owner",   "Owner",   "Toutes permissions, sans restriction",                                                     "#3b82f6"),
        ("admin",   "Admin",   "Accès complet à toutes les pages + gestion des utilisateurs / VAs / paiements",            "#3b82f6"),
        ("va",      "VA",      "Upload contenu, planning posts/stories, gestion des comptes Insta assignés à son identité", "#a855f7"),
        ("chatter", "Chatter", "Vue revenus + planning SFS + historique conversations. Pas d'upload, pas de gestion VAs",  "#fbbf24"),
        ("creator", "Creator", "Modèle (OF/MyM) — vue de ses propres revenus, dashboard perso, validation contenu",         "#10b981"),
        ("sfs",     "SFS Manager", "Création / édition / validation des SFS uniquement (calendrier SFS + preuves AVANT/APRÈS)", "#ec4899"),
    ]
    out = []
    for key, name, desc, color in default_roles:
        custom = role_defs.get(key, {}) if isinstance(role_defs, dict) else {}
        out.append({
            "key": key,
            "name": custom.get("name", name),
            "desc": custom.get("description", desc),
            "color": color,
            "enabled": custom.get("enabled", True),
            "default": True,
        })
    # Roles custom ajoutes par l user (non dans la liste default)
    if isinstance(role_defs, dict):
        for key, info in role_defs.items():
            if any(r["key"] == key for r in out):
                continue
            if not isinstance(info, dict):
                continue
            out.append({
                "key": key,
                "name": info.get("name", key.title()),
                "desc": info.get("description", ""),
                "color": info.get("color", "#6b7280"),
                "enabled": info.get("enabled", True),
                "default": False,
            })
    return out


def _render_employees_table_html() -> str:
    """Tableau Employees style Agency Hess :
    - Header : titre + Batch actions + + Add employee (droite)
    - Filtres : By employee | By Creator | By status | Reset | Search
    - Colonnes : Employee | Role | Status | Actions
    - Modal Edit/Add : Name | Email | Group | Role (no assigned creators)
    """
    users = _load_role_users()
    roles = _get_all_roles()
    role_colors = {r["key"]: r["color"] for r in roles}
    role_names = {r["key"]: r["name"] for r in roles}
    identities = _list_identities() if callable(_list_identities) else []
    # Header de la section : titre a gauche, boutons a droite (style Agency Hess)
    head = (
        "<div style='display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:14px;margin-bottom:18px'>"
        "<h3 style='margin:0;font-size:18px;font-weight:700'>👥 Employees</h3>"
        "<div style='display:flex;gap:10px;align-items:center'>"
        "<button type='button' onclick='toggleBatchActions()' "
        "style='background:#0f0f0f;border:1px solid #2a3f70;color:#3b82f6;padding:9px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:6px'>"
        "Batch actions ▾</button>"
        "<button type='button' onclick='openAddEmployee()' "
        "style='background:#3b82f6;border:0;color:#fff;padding:9px 18px;border-radius:9px;font-size:13px;font-weight:600;cursor:pointer'>"
        "+ Add employee</button>"
        "</div></div>"
    )
    # Ligne de filtres : grille avec 3 colonnes auto-fit pour rester horizontale meme en container etroit
    # 3 champs de filtre puis Reset+Search a droite, tout sur la meme ligne avec wrap responsive
