    @app.route("/mypulslive/push", methods=["POST"])
    def mypulslive_push():
        if not is_auth():
            return redirect("/")
        try:
            import mypuls_scheduler
        except Exception as e:
            return _error(f"❌ Module mypuls_scheduler indispo : {e}", tab="mypulslive")

        try:
            creator_id = int(request.form.get("creator_id") or 0)
        except Exception:
            return _error("❌ Createur invalide", tab="mypulslive")
        if not creator_id:
            return _error("❌ Createur manquant", tab="mypulslive")

        content_type = (request.form.get("content_type") or "both").strip()
        date_start = (request.form.get("date_start") or "").strip()
        date_end = (request.form.get("date_end") or "").strip()
        infinite_mode = (request.form.get("infinite_mode") or "0") == "1"
        post_slots_raw = request.form.get("post_slots_json") or "[]"
        story_slots_raw = request.form.get("story_slots_json") or "[]"
        media_ids_raw = request.form.get("media_ids") or ""
        captions_raw = request.form.get("captions") or ""
        post_action = (request.form.get("post_action") or "delete").strip()
        try:
            post_delete_days = int(request.form.get("post_delete_days") or 2)
        except Exception:
            post_delete_days = 2
        delay_sec = max(1, post_delete_days) * 86400
        # Options toggles
        shuffle_media = (request.form.get("shuffle_media") or "0") == "1"
        randomize_minutes = (request.form.get("randomize_minutes") or "1") == "1"
        # infinite_recycle est l'algorithme par defaut (cycle via modulo) - le flag
        # est pour info, le code recycle de toute facon
        import json as _json
        try:
            post_slots = _json.loads(post_slots_raw)
            if not isinstance(post_slots, list):
                post_slots = []
        except Exception:
            post_slots = []
        try:
            story_slots = _json.loads(story_slots_raw)
            if not isinstance(story_slots, list):
                story_slots = []
        except Exception:
            story_slots = []

        if not date_start:
            return _error("❌ Date de debut manquante", tab="mypulslive")
        if not infinite_mode and not date_end:
            return _error("❌ Date de fin manquante (sinon active Mode infini)", tab="mypulslive")

        def _parse_lines(raw):
            return [ln.strip() for ln in (raw or "").splitlines() if ln.strip()]

        media_ids_str = _parse_lines(media_ids_raw)
        try:
            media_ids = [int(m) for m in media_ids_str]
        except Exception:
            return _error("❌ media_ids doivent etre des entiers", tab="mypulslive")
        if not media_ids:
            return _error("❌ Aucun media_id", tab="mypulslive")

        captions = _parse_lines(captions_raw) or [""]

        # === Mode INFINI : creer une (ou 2) campagnes au lieu d un push one-shot ===
        if infinite_mode:
            try:
                import mypuls_campaigns
                import mypuls
            except Exception as e:
                return _error(f"❌ Module campagnes indispo : {e}", tab="mypulslive")
            creators = mypuls.list_creators().get("creators", {})
            cname = ""
            for n, cid in creators.items():
                if int(cid) == creator_id:
                    cname = n
                    break
            # Pour chaque type configure (post / story), on cree une campagne.
            # content_type="both" -> 2 campagnes si les 2 slots sont remplis.
            campaigns_to_create = []
            if content_type in ("post", "both") and post_slots:
                campaigns_to_create.append(("post", post_slots))
            if content_type in ("story", "both") and story_slots:
                campaigns_to_create.append(("story", story_slots))
            if not campaigns_to_create:
                return _error(
                    "❌ Mode infini : configure au moins un slot post ou story (et clique sur l'onglet correspondant)",
                    tab="mypulslive",
                )
            results = []
            for ctype, slots in campaigns_to_create:
                res = mypuls_campaigns.create_campaign(
                    creator_id=creator_id,
                    creator_name=cname,
                    campaign_type=ctype,
                    slots=slots,
                    media_ids=media_ids,
                    captions=captions,
                    options={"shuffle_media": shuffle_media, "randomize_minutes": randomize_minutes},
                    post_action=post_action,
                    delay_sec=delay_sec,
                    start_date=date_start,
                )
                if not res.get("ok"):
                    return _error(f"❌ Creation campagne {ctype} : {res.get('error', '?')}", tab="mypulslive")
                results.append((ctype, res.get("planned", 0)))
            msg_parts = [f"♾️ {n} {ct}(s) sur les 2 prochains jours" for ct, n in results]
            return _success(
                f"Campagne(s) lancée(s) pour <b>{cname}</b> : "
                + " · ".join(msg_parts)
                + ". Le cron étend de 2 jours toutes les heures.",
                tab="mypulslive",
            )

        summary_parts = []
        all_errors = []

        # Story push
        if content_type in ("story", "both") and story_slots:
            # story_slots est une liste de "HH:MM" strings
            res = mypuls_scheduler.bulk_schedule_stories(
                creator_id=creator_id,
                media_ids=media_ids,
                date_start=date_start,
                date_end=date_end,
                story_slots=story_slots,
                shuffle_media=shuffle_media,
                randomize_minutes=randomize_minutes,
            )
            summary_parts.append(
                f"📱 Stories : {res.get('planned', 0)} OK / {res.get('failed', 0)} fail"
            )
            if res.get("errors"):
                all_errors.extend(res["errors"][:3])

        # Post push
        if content_type in ("post", "both") and post_slots:
            # post_slots est [{time:"HH:MM", visibility:"public"|"private"}, ...]
            res = mypuls_scheduler.bulk_schedule_posts(
                creator_id=creator_id,
                media_ids=media_ids,
                captions=captions,
                date_start=date_start,
                date_end=date_end,
                post_slots=post_slots,
                action=post_action,
                delay_sec=delay_sec,
                shuffle_media=shuffle_media,
                randomize_minutes=randomize_minutes,
            )
            summary_parts.append(
                f"📰 Posts : {res.get('planned', 0)} OK / {res.get('failed', 0)} fail"
            )
            if res.get("errors"):
                all_errors.extend(res["errors"][:3])

        if not summary_parts:
            return _error("❌ Aucun slot configure pour le type choisi", tab="mypulslive")

        msg = "✅ Push live termine — " + " | ".join(summary_parts)
        if all_errors:
            msg += " | Premieres erreurs : " + "; ".join(all_errors[:3])
        return _success(msg, tab="mypulslive")

    # ============ BULK DELETE ALL CREATORS — async with progress polling ============
    # Le bulk delete peut prendre 5+ minutes (1 list + N delete per creator).
    # On le fait en background thread + endpoint de status pour feedback temps reel.
    # _BULK_DELETE_JOBS : {job_id: {status, creators_scanned, total, current,
    #   deleted, failed, errors, cancelled, started_at}}
    if not hasattr(app, "_bulk_delete_jobs"):
        app._bulk_delete_jobs = {}
        app._bulk_delete_lock = threading.Lock()

    def _run_bulk_delete_job(job_id, creator_ids, start_iso, end_iso):
        """Worker thread : phase 1 list events, phase 2 delete events."""
        import mypuls_scheduler
        job = app._bulk_delete_jobs[job_id]
        try:
            # Phase 1 : list
            job["status"] = "listing"
            all_events = []  # [(creator_id, event_id), ...]
            for cid in creator_ids:
                if job["cancelled"]:
                    job["status"] = "cancelled"
                    return
                try:
                    lst = mypuls_scheduler.list_calendar_events([cid], start_iso, end_iso)
                    if lst.get("ok"):
                        for ev in lst.get("events") or []:
                            eid = ev.get("id")
                            if eid:
                                all_events.append((cid, int(eid)))
                    else:
                        job["errors"].append(f"#{cid} list: {lst.get('error', '?')}")
                except Exception as e:
                    job["errors"].append(f"#{cid} list err: {e}")
                job["creators_scanned"] += 1
            job["total"] = len(all_events)
            # Phase 2 : delete
            job["status"] = "deleting"
            for cid, eid in all_events:
                if job["cancelled"]:
                    job["status"] = "cancelled"
                    return
                try:
                    res = mypuls_scheduler.delete_event(eid)
                    if res.get("ok"):
                        job["deleted"] += 1
                    else:
                        job["failed"] += 1
                        if len(job["errors"]) < 20:
                            job["errors"].append(f"#{cid} ev#{eid}: {res.get('error', '?')}")
                except Exception as e:
                    job["failed"] += 1
                    if len(job["errors"]) < 20:
                        job["errors"].append(f"#{cid} ev#{eid}: {e}")
                job["current"] += 1
            job["status"] = "done"
        except Exception as e:
            job["status"] = "error"
            job["errors"].append(f"fatal: {e}")
        finally:
            import time as _t
            job["finished_at"] = _t.time()

    @app.route("/mypulslive/delete_all_creators/start", methods=["POST"])
    def mypulslive_delete_all_creators_start():
        from flask import jsonify
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        try:
            import mypuls_creator_settings as mcs
            import seed_media_pools
        except Exception as e:
            return jsonify({"ok": False, "error": f"module indispo : {e}"})

        g = mcs.get_global_settings()
        date_start = (g.get("start_date") or "").strip()
        date_end = (g.get("end_date") or "").strip()
        body = (request.get_json(silent=True) or {})
        if body.get("start_date"): date_start = body["start_date"]
        if body.get("end_date"): date_end = body["end_date"]
        if not date_start or not date_end:
            return jsonify({"ok": False, "error": "Dates manquantes"})

        start_iso = f"{date_start}T00:00:00"
        end_iso = f"{date_end}T23:59:59"
        creator_ids = list(seed_media_pools.MEDIA_SEEDS.keys())

        import uuid, time as _t
        job_id = uuid.uuid4().hex[:12]
        with app._bulk_delete_lock:
            # Cleanup vieux jobs (> 1h) pour pas que la dict grossisse a l infini
            now = _t.time()
            old = [k for k, v in app._bulk_delete_jobs.items() if v.get("finished_at", now) < now - 3600]
            for k in old:
                app._bulk_delete_jobs.pop(k, None)
            app._bulk_delete_jobs[job_id] = {
                "status": "queued",
                "creators_scanned": 0,
                "total": 0,
                "current": 0,
                "deleted": 0,
                "failed": 0,
                "errors": [],
                "cancelled": False,
                "started_at": _t.time(),
                "creators_count": len(creator_ids),
                "date_start": date_start,
                "date_end": date_end,
            }
        threading.Thread(
            target=_run_bulk_delete_job,
            args=(job_id, creator_ids, start_iso, end_iso),
            daemon=True,
            name=f"bulk-delete-{job_id}",
        ).start()
        return jsonify({"ok": True, "job_id": job_id})

    @app.route("/mypulslive/delete_all_creators/status/<job_id>", methods=["GET"])
    def mypulslive_delete_all_creators_status(job_id):
        from flask import jsonify
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        job = app._bulk_delete_jobs.get(job_id)
        if not job:
            return jsonify({"ok": False, "error": "job introuvable (peut-etre expire)"})
        # Renvoie une copie sans champs internes
        return jsonify({
            "ok": True,
            "job": {k: v for k, v in job.items() if k != "cancelled"},
        })

