    @app.route("/mypulslive/push_all_creators", methods=["POST"])
    def mypulslive_push_all_creators():
        """Bulk push : applique le planning GLOBAL (slots + dates) a tous les
        createurs qui ont au moins 1 media_pool_posts dans leur config.

        Utilise par le bouton 'Pousser tous les createurs' pour eviter de
        cliquer 9x. Operation potentiellement longue -> renvoie JSON pour
        que le front affiche un loader.
        """
        from flask import jsonify
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        try:
            import mypuls_creator_settings as mcs
            import mypuls_scheduler
            import seed_media_pools
        except Exception as e:
            return jsonify({"ok": False, "error": f"module indispo : {e}"})

        # Lit le planning GLOBAL (slots + dates)
        g = mcs.get_global_settings()
        post_slots = (g.get("posts") or {}).get("slots") or []
        story_slots = (g.get("stories") or {}).get("slots") or []
        date_start = (g.get("start_date") or "").strip()
        date_end = (g.get("end_date") or "").strip()
        if not date_start or not date_end:
            return jsonify({"ok": False, "error": "Dates globales non configurees"})
        if not post_slots and not story_slots:
            return jsonify({"ok": False, "error": "Aucun slot global configure"})

        # Stories : convertir au format attendu par bulk_schedule_stories
        # ([{time:"HH:MM", audience:"..."}] -> [{time:"HH:MM", audience:"..."}])
        # (les audiences sont preservees telles quelles)

        creator_ids = list(seed_media_pools.MEDIA_SEEDS.keys())
        results = []
        total_planned_posts = 0
        total_planned_stories = 0
        total_failed = 0
        first_errors: list = []

        for cid in creator_ids:
            try:
                c_settings = mcs.get_creator_settings(cid)
                media_pool = c_settings.get("media_pool_posts") or []
                captions = c_settings.get("captions") or [""]
                if not media_pool:
                    results.append({"cid": cid, "skip": "no_media"})
                    continue
                # Cast media_ids en int (le scheduler veut des ints)
                try:
                    media_ids = [int(m) for m in media_pool]
                except Exception:
                    results.append({"cid": cid, "skip": "bad_media_ids"})
                    continue
                summary = {"cid": cid, "posts": 0, "stories": 0, "failed": 0}
                # Push posts
                if post_slots:
                    res = mypuls_scheduler.bulk_schedule_posts(
                        creator_id=cid,
                        media_ids=media_ids,
                        captions=captions,
                        date_start=date_start,
                        date_end=date_end,
                        post_slots=post_slots,
                        action="delete",
                        delay_sec=172800,
                        shuffle_media=False,
                        randomize_minutes=True,
                    )
                    summary["posts"] = res.get("planned", 0)
                    summary["failed"] += res.get("failed", 0)
                    total_planned_posts += summary["posts"]
                    total_failed += res.get("failed", 0)
                    if res.get("errors"):
                        first_errors.extend(res["errors"][:2])
                # Push stories
                if story_slots:
                    res = mypuls_scheduler.bulk_schedule_stories(
                        creator_id=cid,
                        media_ids=media_ids,
                        date_start=date_start,
                        date_end=date_end,
                        story_slots=story_slots,
                        shuffle_media=False,
                        randomize_minutes=True,
                    )
                    summary["stories"] = res.get("planned", 0)
                    summary["failed"] += res.get("failed", 0)
                    total_planned_stories += summary["stories"]
                    total_failed += res.get("failed", 0)
                    if res.get("errors"):
                        first_errors.extend(res["errors"][:2])
                results.append(summary)
            except Exception as e:
                results.append({"cid": cid, "error": str(e)})
                first_errors.append(f"#{cid}: {e}")

        return jsonify({
            "ok": True,
            "summary": {
                "creators_processed": len([r for r in results if "posts" in r or "stories" in r]),
                "creators_skipped": len([r for r in results if "skip" in r]),
                "total_posts_planned": total_planned_posts,
                "total_stories_planned": total_planned_stories,
                "total_failed": total_failed,
                "date_start": date_start,
                "date_end": date_end,
            },
            "results": results,
            "first_errors": first_errors[:10],
        })

    @app.route("/schedule/generate", methods=["POST"])
    def schedule_generate():
        if not is_auth():
            return redirect("/")
        try:
            import schedule_xlsx
        except Exception as e:
            return _error(f"❌ Module schedule_xlsx indispo (pip install openpyxl ?) : {e}", tab="schedule")

        model_name = (request.form.get("model_name") or "").strip()
        date_start = (request.form.get("date_start") or "").strip()
        date_end = (request.form.get("date_end") or "").strip()
        public_hours = (request.form.get("public_hours") or "").strip()
        private_hours = (request.form.get("private_hours") or "").strip()
        media_ids = request.form.get("media_ids") or ""
        captions = request.form.get("captions") or ""
        # Toggles (style MyPuls Live) : checked == "on" pour les checkboxes
        # On accepte aussi "1" pour compat avec des inputs hidden
        def _flag(name, default=False):
            v = (request.form.get(name) or "").strip().lower()
            if v in ("on", "1", "true", "yes"): return True
            if v in ("off", "0", "false", "no", ""):
                return default if v == "" else False
            return default
        recycle_infinite = _flag("recycle_infinite", default=True)
        shuffle_media = _flag("shuffle_media", default=False)
        randomize_minutes = _flag("randomize_minutes", default=True)
        # Stories : JSON [{time:"HH:MM", audience:"everyone"|"subscribers"|...}]
        # Si absent ou liste vide -> pas de sheet Stories generee.
        story_slots_raw = request.form.get("story_slots_json") or "[]"
        import json as _json_sx
        try:
            story_slots_list = _json_sx.loads(story_slots_raw)
            if not isinstance(story_slots_list, list):
                story_slots_list = []
        except Exception:
            story_slots_list = []

        if not model_name:
            return _error("❌ Nom du modele manquant", tab="schedule")
        if not date_start or not date_end:
            return _error("❌ Dates manquantes", tab="schedule")
        if not media_ids.strip():
            return _error("❌ Aucun media_id fourni", tab="schedule")
        if not public_hours and not private_hours and not story_slots_list:
            return _error("❌ Au moins un slot (post public/prive ou story) doit etre indique", tab="schedule")

        try:
            xlsx_bytes, filename = schedule_xlsx.generate_xlsx(
                model_name=model_name,
                date_start=date_start,
                date_end=date_end,
                public_hours_raw=public_hours,
                private_hours_raw=private_hours,
                media_ids_raw=media_ids,
                captions_raw=captions,
                story_slots=story_slots_list,
                recycle_infinite=recycle_infinite,
                shuffle_media=shuffle_media,
                randomize_minutes=randomize_minutes,
            )
        except ValueError as e:
            return _error(f"❌ {e}", tab="schedule")
        except Exception as e:
            return _error(f"❌ Generation echouee : {type(e).__name__}: {e}", tab="schedule")

        from flask import Response
        resp = Response(
            xlsx_bytes,
            mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        )
        # ASCII-safe disposition (RFC 5987 for unicode filename)
        try:
            ascii_name = filename.encode("ascii", "ignore").decode("ascii") or "template_import.xlsx"
        except Exception:
            ascii_name = "template_import.xlsx"
        from urllib.parse import quote
        resp.headers["Content-Disposition"] = (
            f"attachment; filename=\"{ascii_name}\"; filename*=UTF-8''" + quote(filename)
        )
        return resp

