    def settings_role_delete():
        if not is_auth():
            return redirect("/")
        key = (request.form.get("role_key") or "").strip()
        if not key or key == "owner":
            return _error("❌ Impossible de supprimer ce rôle")
        defs = _load_role_definitions()
