    @app.route("/va/add_manual", methods=["POST"])
    def va_add_manual():
        """Cree un VA manuel (non-Discord). Body : identity, display_name, [handle_0..2]."""
        from flask import jsonify
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        identity = (request.form.get("identity") or "").strip().lower()
        display_name = (request.form.get("display_name") or "").strip()
        if not identity or not display_name:
            return jsonify({"ok": False, "error": "identity + display_name requis"}), 400
        if identity not in _list_identities():
            return jsonify({"ok": False, "error": f"identite '{identity}' introuvable"}), 400
        import secrets as _secrets, time as _t
        uid = "manual_" + _secrets.token_hex(4)
        users = _load_users()
        users[uid] = {
            "identity": identity,
            "manual": True,
            "display_name": display_name,
            "channel_id": None,
            "auto_post": False,
            "added_at": int(_t.time()),
        }
        _save_users(users)
        # Bulk handles : textarea avec 1 par ligne (ou separes par virgule)
        bulk_raw = request.form.get("bulk_handles", "")
        accounts = []
        seen = set()
        for line in bulk_raw.replace(",", "\n").splitlines():
            h_norm = _normalize_insta_handle(line.strip())
            if h_norm and h_norm not in seen:
                seen.add(h_norm)
                accounts.append({
                    "handle": h_norm,
                    "email": "",
                    "password": "",
                    "totp_seed": "",
                })
        # Slots indexes (handle_0..N) avec creds en option pour les 3 premiers
        for i in range(20):
            h_form = request.form.get(f"handle_{i}", "")
            if h_form.strip():
                h_norm = _normalize_insta_handle(h_form)
                if h_norm and h_norm not in seen:
                    seen.add(h_norm)
                    accounts.append({
                        "handle": h_norm,
                        "email": "",
                        "password": request.form.get(f"password_{i}", ""),
                        "totp_seed": request.form.get(f"totp_seed_{i}", ""),
                    })
        if accounts:
            _set_insta_3_for_va(uid, accounts)
        return jsonify({"ok": True, "uid": uid, "user": users[uid], "n_accounts": len(accounts)})

    @app.route("/va/set_insta_3", methods=["POST"])
    def va_set_insta_3():
        """Stocke les 3 comptes Instagram d'un VA avec credentials.

        Body (3 slots, suffixe 0/1/2) :
        - user_id
        - handle_0, email_0, password_0, totp_seed_0
        - handle_1, email_1, password_1, totp_seed_1
        - handle_2, email_2, password_2, totp_seed_2

        Compat : accepte aussi handles[] (legacy /insta Discord, handle-only).
        """
        from flask import jsonify
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        uid = (request.form.get("user_id") or "").strip()
        if not uid:
            return jsonify({"ok": False, "error": "user_id manquant"}), 400
        # Mode legacy si handles[] est fourni (Discord)
        legacy_handles = request.form.getlist("handles")
        if legacy_handles:
            accounts = legacy_handles
        else:
            accounts = []
            for i in (0, 1, 2):
                accounts.append({
                    "handle": request.form.get(f"handle_{i}", ""),
                    "email": request.form.get(f"email_{i}", ""),
                    "password": request.form.get(f"password_{i}", ""),
                    "totp_seed": request.form.get(f"totp_seed_{i}", ""),
                })
        try:
            _set_insta_3_for_va(uid, accounts)
            saved = _get_insta_3_for_va(uid)
        except Exception as e:
            return jsonify({"ok": False, "error": str(e)})
        return jsonify({"ok": True, "accounts": saved})

