    @app.route("/insta/refresh_now", methods=["POST"])
    def insta_refresh_now():
        """Trigger un refresh complet en arriere-plan.
        Retourne immediatement, le refresh tourne en thread.

        Probe directement _REFRESH_LOCK (au lieu de juste lire le state file)
        pour eviter le TOCTOU : si un refresh tourne deja (daemon 3x/jour ou
        autre clic), on refuse proprement au lieu de spawn un thread qui
        no-op et renvoie quand meme ok:True."""
        from flask import jsonify
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        # Probe non-bloquant : si on n arrive pas a prendre le lock, un refresh
        # tourne deja. On relache aussitot (le thread bg le re-prendra).
        if not _REFRESH_LOCK.acquire(blocking=False):
            st = _load_refresh_state()
            return jsonify({"ok": False, "error": "Un refresh est deja en cours", "state": st})
        _REFRESH_LOCK.release()
        # Lance en thread background
        import threading as _th2
        def _bg():
            try:
                _run_daily_insta_refresh()
            except Exception as e:
                print(f"[insta-refresh:manual] crash: {e}", flush=True)
        t = _th2.Thread(target=_bg, daemon=True, name="insta-refresh-manual")
        t.start()
        return jsonify({"ok": True, "started": True, "handles": len(_all_tracked_handles())})

    @app.route("/external/stats_batch", methods=["POST"])
    def external_stats_batch():
        """Stats pour N handles en parallel (jusqu'a 50 par batch).
        Body : handles=h1,h2,h3,... + force=1 (optionnel)."""
        from flask import jsonify
        from concurrent.futures import ThreadPoolExecutor
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        raw = request.form.get("handles") or request.args.get("handles") or ""
        force = (request.form.get("force") or request.args.get("force") or "").strip() == "1"
        handles = [x.strip() for x in raw.split(",") if x.strip()][:50]
        if not handles:
            return jsonify({"ok": True, "results": []})
        # Parallel scrape avec 4 workers (evite le rate-limit IG 429)
        results = {}
        with ThreadPoolExecutor(max_workers=4) as ex:
            future_map = {ex.submit(_compute_insta_3_stats, h, force): h for h in handles}
            for fut in future_map:
                h = future_map[fut]
                try:
                    results[h] = fut.result(timeout=30)
                except Exception as e:
                    results[h] = {"error": f"timeout: {e}"}
        return jsonify({"ok": True, "results": [{"handle": h, "stats": results.get(h, {})} for h in handles]})

    @app.route("/va/insta_3_stats", methods=["GET"])
    def va_insta_3_stats():
        """Retourne pour chaque handle d un VA : daily/weekly/biweekly views.
        Cache 1h. ?force=1 pour bypass."""
        from flask import jsonify
        if not is_auth():
            return jsonify({"ok": False, "error": "unauth"}), 401
        uid = (request.args.get("user_id") or "").strip()
        force = (request.args.get("force") or "").strip() == "1"
        if not uid:
            return jsonify({"ok": False, "error": "user_id manquant"}), 400
        accounts = _get_insta_3_for_va(uid)
        out = []
        for acc in accounts:
            h = (acc or {}).get("handle") or ""
            if not h:
                out.append({"handle": "", "stats": None})
                continue
            stats = _compute_insta_3_stats(h, force=force)
            out.append({"handle": h, "stats": stats})
        return jsonify({"ok": True, "results": out})

